/* 最长回文拼接：利用哈希表快速查找可配对字符串 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    unordered_set<string> strs;
    vector<string> originals(n);

    for (int i = 0; i < n; ++i) {
        cin >> originals[i];
        strs.insert(originals[i]);
    }

    int max_len = 0;

    for (const string& s : originals) {
        string rev_s(s.rbegin(), s.rend());

        // 情况1：完全反转匹配（s + rev_s 或 rev_s + s）
        if (strs.count(rev_s) && rev_s != s) {
            max_len = max(max_len, 2 * (int)s.size());
        }

        // 情况2：部分匹配（s的前缀是t的后缀的反转）
        // 检查所有可能的前缀/后缀
        for (int len = 1; len < (int)s.size(); ++len) {
            string prefix = s.substr(0, len);
            string suffix = s.substr(len);
            string rev_prefix(prefix.rbegin(), prefix.rend());
            string rev_suffix(suffix.rbegin(), suffix.rend());

            // s + t 形成回文：suffix需要是回文，且rev_prefix存在
            if (is_palindrome(suffix) && strs.count(rev_prefix)) {
                max_len = max(max_len, (int)(s.size() + prefix.size()));
            }

            // t + s 形成回文：prefix需要是回文，且rev_suffix存在
            if (is_palindrome(prefix) && strs.count(rev_suffix)) {
                max_len = max(max_len, (int)(s.size() + suffix.size()));
            }
        }
    }

    cout << max_len << '\n';
    return 0;
}

// 辅助函数：判断字符串是否为回文
bool is_palindrome(const string& s) {
    int left = 0, right = (int)s.size() - 1;
    while (left < right) {
        if (s[left] != s[right]) return false;
        ++left;
        --right;
    }
    return true;
}

