/*
比特彩票最大奖金计算
核心算法：贪心+数位DP思想
关键技术：按位处理，优先在高位放置1
*/
#include <bits/stdc++.h>
using namespace std;
using ll = long long;

int main() {
    int n;
    ll m;
    cin >> n >> m;
    vector<ll> a(n);
    for (int i = 0; i < n; ++i) cin >> a[i];

    ll res = 0;
    // 从最高位到最低位逐步确定
    for (int bit = 60; bit >= 0; --bit) {
        ll mask = 1LL << bit;
        if ((m & mask) == 0) continue; // 当前位不能选1

        // 尝试在当前位放1，计算可能的收益
        ll temp = res | mask;
        // 检查是否存在n个不同的数<=m且包含temp
        // 需要满足 temp + (n-1) <= m
        if (temp + n - 1 > m) continue;

        // 计算选择该位的总收益
        ll gain = 0;
        for (int i = 0; i < n; ++i) {
            int cnt = __builtin_popcountll(temp + i);
            gain += a[i] * cnt;
        }

        // 计算不选该位的总收益（所有数都小于mask）
        ll no_gain = 0;
        ll max_no = min(m, mask - 1);
        if (max_no >= n - 1) { // 存在足够数
            for (int i = 0; i < n; ++i) {
                int cnt = __builtin_popcountll(max_no - (n - 1) + i);
                no_gain += a[i] * cnt;
            }
        } else {
            no_gain = LLONG_MIN; // 不可行
        }

        if (gain > no_gain) {
            res = temp;
        }
    }

    // 最终计算选择res的序列
    ll final_ans = 0;
    for (int i = 0; i < n; ++i) {
        final_ans += a[i] * __builtin_popcountll(res + i);
    }
    cout << final_ans << endl;

    return 0;
}

