1. 修正了"不选该位"的错误计算方式
2. 引入辅助函数计算特定位模式下的收益
3. 确保序列严格递增且不超限
*/
#include <bits/stdc++.h>
using namespace std;
using ll = long long;

// 计算在给定起始数base的情况下，n个连续数的总收益
ll calculate_gain(const vector<ll>& a, ll base) {
    ll res = 0;
    for (int i = 0; i < a.size(); ++i) {
        res += a[i] * __builtin_popcountll(base + i);
    }
    return res;
}

