        if (temp + n - 1 > m) continue;

        // 计算选择该位的总收益
        ll gain = calculate_gain(a, temp);

        // 计算不选该位的总收益（所有数的当前位必须为0）
        ll no_gain = 0;
        ll upper = (res | (mask - 1)); // 当前位为0，低位全1
        if (upper >= n - 1) { // 存在足够数
            ll start = upper - (n - 1);
            no_gain = calculate_gain(a, start);
        } else {
            no_gain = LLONG_MIN; // 不可行
        }

