/* 
最长回文拼接
修复说明：
1. 优化了前缀/后缀检查逻辑，只检查有效的回文分割点
2. 预处理所有字符串的逆序版本
3. 减少不必要的重复计算
*/
#include <bits/stdc++.h>
using namespace std;

bool is_palindrome(const string &s) {
    int l = 0, r = s.size() - 1;
    while (l < r) {
        if (s[l++] != s[r--]) return false;
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<string> strs(n);
    unordered_map<string, int> str_map; // string到长度的映射

    for (int i = 0; i < n; ++i) {
        cin >> strs[i];
        str_map[strs[i]] = strs[i].size();
    }

    int max_len = 0;
    for (const auto &s : strs) {
        string rev_s(s.rbegin(), s.rend());

        // 情况1：存在完全逆序的字符串
        if (str_map.count(rev_s) && rev_s != s) {
            max_len = max(max_len, (int)s.size() * 2);
        }

        // 情况2：检查前缀逆序（剩余部分必须是回文）
        for (int len = 1; len <= s.size(); ++len) {
            string remaining = s.substr(len);
            if (!is_palindrome(remaining)) continue;

            string prefix = s.substr(0, len);
            string rev_prefix(prefix.rbegin(), prefix.rend());
            if (str_map.count(rev_prefix)) {
                max_len = max(max_len, (int)s.size() + (int)rev_prefix.size());
            }
        }

        // 情况3：检查后缀逆序（剩余部分必须是回文）
        for (int len = 1; len <= s.size(); ++len) {
            string remaining = s.substr(0, s.size() - len);
            if (!is_palindrome(remaining)) continue;

            string suffix = s.substr(s.size() - len);
            string rev_suffix(suffix.rbegin(), suffix.rend());
            if (str_map.count(rev_suffix)) {
                max_len = max(max_len, (int)s.size() + (int)rev_suffix.size());
            }
        }
    }

    cout << max_len << '\n';
    return 0;
}

